#include<bits/stdc++.h>
using namespace std;
long long dp[30005],t,m,a[25],b[25];
int main()
{
	cin>>t>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i]>>b[i];
        b[i]*=a[i];
	}
	for(int i=1;i<=m;i++)
	{
		for(int j=t;j>=a[i];j--) dp[j]=max(dp[j],b[i]+dp[j-a[i]]);
	}
	cout<<dp[t];
	return 0;
}
